func hasLabel(b Bead, label string) bool {
	for _, existing := range b.Labels {
		if existing == label {
			return true
		}
	}
	return false
}

func addLabel(b *Bead, label string) {
	for _, existing := range b.Labels {
		if existing == label {
			return
		}
	}
	b.Labels = append(b.Labels, label)
}

func removeLabel(b *Bead, label string) {
	out := b.Labels[:0]
	for _, existing := range b.Labels {
		if existing != label {
			out = append(out, existing)
		}
	}
	b.Labels = out
}

