108			p.ClearFields = noChangesFieldsPresent(b)
109			p.RemoveLabels = noChangesLabelsPresent(b)
110			return p, len(p.ClearFields) > 0 || len(p.RemoveLabels) > 0
111		}
112	
113		if isSuccessEvent(latest) && hasNoChangesResidue(b) {
114			p.Reason = "latest terminal success supersedes stale no_changes lifecycle metadata"
115			p.ClearFields = noChangesFieldsPresent(b)
116			p.RemoveLabels = noChangesLabelsPresent(b)
117			return p, len(p.ClearFields) > 0 || len(p.RemoveLabels) > 0
118		}
119	
120		if latest.Kind == "no_changes_verified" && b.Status != StatusClosed {
121			p.Reason = "verified no_changes evidence closes as already_satisfied"
122			p.ClearFields = noChangesFieldsPresent(b)
123			p.RemoveLabels = noChangesLabelsPresent(b)
124			p.CloseSatisfied = true
125			return p, true
126		}
127	
128		if isNoViableProviderLifecycleEvent(latest) {
129			if hasLabel(b, LabelNeedsInvestigation) {
130				p.Reason = "latest no_viable_provider execution supersedes stale needs_investigation label"
131				p.RemoveLabels = append(p.RemoveLabels, LabelNeedsInvestigation)
132				return p, true
133			}
134		}
135	
136		if hasLabel(b, LabelNeedsInvestigation) || latest.Kind == "no_changes_needs_investigation" {
137			if hasRetryAfter(b) || hasAnyExtra(b, ExtraLastStatus, ExtraLastDetail) {
138				p.Reason = "needs_investigation is non-retryable; clear cooldown metadata"
139				p.ClearFields = noChangesFieldsPresent(b)
140				if !hasLabel(b, LabelNeedsInvestigation) {
141					p.AddLabels = append(p.AddLabels, LabelNeedsInvestigation)
142				}
143				return p, len(p.ClearFields) > 0 || len(p.AddLabels) > 0
144			}
145		}
146	
147		if isExpiredRetryAfter(b, now) {
148			p.Reason = "expired retry-after metadata no longer blocks execution"
149			p.ClearFields = []string{ExtraRetryAfter}
150			return p, true
151		}
152	
153		if isContainerBead(b, childCount) && noChangesCount(b) > 0 {
154			if b.Extra != nil {
155				if eligible, ok := b.Extra[ExtraExecutionElig].(bool); ok && !eligible {
156					return ReconcilePlan{}, false
157				}
158			}
159			p.Reason = "parent/epic work is owned by child beads"
160			p.SetFields = map[string]any{
161				ExtraExecutionElig:   false,
162				ExtraExecutionReason: "parent/epic container; execute child beads first",
163			}
164			return p, true
165		}
166	
167		return ReconcilePlan{}, false
168	}
