244	func isSuccessEvent(e BeadEvent) bool {
245		if e.Kind != "execute-bead" {
246			return false
247		}
248		summary := strings.TrimSpace(e.Summary)
249		return summary == "success" || summary == "already_satisfied"
250	}
251	
252	func isNoViableProviderLifecycleEvent(e BeadEvent) bool {
253		if e.Kind != "execute-bead" {
254			return false
255		}
256		if strings.TrimSpace(e.Summary) != "execution_failed" {
257			return false
258		}
259		body := strings.ToLower(e.Body)
260		return strings.Contains(body, "outcome_reason=no_viable_provider") ||
261			strings.Contains(body, "no viable provider")
262	}
263	
264	func hasNoChangesResidue(b Bead) bool {
265		return len(noChangesFieldsPresent(b)) > 0 || len(noChangesLabelsPresent(b)) > 0
266	}
267	
268	func hasClosedNoChangesResidue(b Bead) bool {
269		return len(noChangesLabelsPresent(b)) > 0 || hasAnyExtra(b, ExtraRetryAfter, ExtraLastStatus, ExtraLastDetail)
270	}
